### 4. EXAMPLE: How a Nested Loop Join Works

**File:** `/workspace/src/backend/executor/nodeNestloop.c` (lines 59-200)

```c
static TupleTableSlot *
ExecNestLoop(PlanState *pstate)
{
    NestLoopState *node = castNode(NestLoopState, pstate);
    PlanState *innerPlan = innerPlanState(node);
    PlanState *outerPlan = outerPlanState(node);

    for (;;)
    {
        /* If we don't have an outer tuple, get the next one */
        if (node->nl_NeedNewOuter)
        {
            /*
             * This calls the outer plan's ExecProcNode function
             * (e.g., ExecSeqScan if the outer plan is a SeqScan)
             */
            outerTupleSlot = ExecProcNode(outerPlan);

            if (TupIsNull(outerTupleSlot))
                return NULL;  /* No more outer tuples */

            /* Store outer tuple and rescan inner plan */
            econtext->ecxt_outertuple = outerTupleSlot;
            ExecReScan(innerPlan);
            node->nl_NeedNewOuter = false;
        }

        /*
         * Get next inner tuple
         * This calls the inner plan's ExecProcNode function
         */
        innerTupleSlot = ExecProcNode(innerPlan);
        econtext->ecxt_innertuple = innerTupleSlot;

        if (TupIsNull(innerTupleSlot))
        {
            /* No more inner tuples for this outer tuple */
            node->nl_NeedNewOuter = true;

            /* Handle outer joins (LEFT/ANTI) */
            if (!node->nl_MatchedOuter &&
                (node->js.jointype == JOIN_LEFT ||
                 node->js.jointype == JOIN_ANTI))
            {
                econtext->ecxt_innertuple = node->nl_NullInnerTupleSlot;

                if (otherqual == NULL || ExecQual(otherqual, econtext))
                    return ExecProject(node->js.ps.ps_ProjInfo);
            }
            continue;
        }

        /* Check join condition */
        if (ExecQual(joinqual, econtext))
        {
            /* Qualification succeeded, apply projection and return */
            return ExecProject(node->js.ps.ps_ProjInfo);
        }
    }
}
```

**Tuple flow diagram:**
```
ExecutePlan() [Main loop]
    |
    v
ExecProcNode(NestLoopState)
    |
    +---> ExecProcNode(OuterPlanState)  [e.g., SeqScan]
    |         |
    |         v
    |     Get tuple from table
    |     [return slot1]
    |
    +---> Store in ecxt_outertuple
    |
    +---> ExecProcNode(InnerPlanState)  [e.g., SeqScan]
    |         |
    |         v
    |     Get tuple from table
    |     [return slot2]
    |
    +---> Check join condition on (slot1, slot2)
    |
    +---> Apply projection
    |
    v
    [return result slot]
```

